/**
 * Canonical link type definitions and link priority/normalization utilities.
 * LinkType is defined here (not in IconButton) so both IconButton and card
 * components can import it without circular dependencies.
 */
export const linkPriority = [
    "website",
    "linkedin",
    "github",
    "email",
    "scheduling",
    "googleScholar",
    "orcid",
    "documentation",
    "paper",
    "purchase",
    "rental",
    "demo",
    "pypi",
    "npm",
    "pdf",
    "doi",
    "arxiv",
    "code",
    "data",
    "video",
    "registration",
    "program",
    "proceedings",
    "recordings",
    "twitter",
    "bluesky",
    "mastodon",
    "phone",
];
const linkAliasMap = {
    docs: "documentation",
    documentation: "documentation",
    "google-scholar": "googleScholar",
    paper: "documentation",
    pdf: "documentation",
};
/** Normalizes a link href based on its type (e.g. github username → full URL). */
export function normalizeLinkHref(type, value) {
    const canonical = type in linkAliasMap
        ? linkAliasMap[type]
        : type;
    if (value.startsWith("http://") || value.startsWith("https://")) {
        return value;
    }
    switch (canonical) {
        case "email":
            return value.startsWith("mailto:") ? value : `mailto:${value}`;
        case "phone":
            return value.startsWith("tel:") ? value : `tel:${value}`;
        case "github":
            return `https://github.com/${value}`;
        case "linkedin":
            return value.includes("linkedin.com")
                ? value
                : `https://www.linkedin.com/in/${value}`;
        case "twitter":
            return `https://twitter.com/${value.replace(/^@/, "")}`;
        case "bluesky":
            return `https://bsky.app/profile/${value.replace(/^@/, "")}`;
        case "pypi":
            return `https://pypi.org/project/${value}`;
        case "npm":
            return `https://www.npmjs.com/package/${value}`;
        case "googleScholar":
            return value.includes("scholar.google")
                ? value
                : `https://scholar.google.com/citations?user=${value}`;
        case "orcid":
            return value.includes("orcid.org")
                ? value
                : `https://orcid.org/${value}`;
        case "arxiv":
            return value.includes("arxiv.org")
                ? value
                : `https://arxiv.org/abs/${value}`;
        case "doi":
            return value.includes("doi.org")
                ? value
                : `https://doi.org/${value}`;
        default:
            return value;
    }
}
